140	/// Read an env-file value or None if absent. Mirrors pristine's helper —
141	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
142	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
143	    let content = std::fs::read_to_string(path).ok()?;
144	    let prefix = format!("{}=", key);
145	    for line in content.lines() {
146	        let trimmed = line.trim_start();
147	        if trimmed.starts_with('#') {
148	            continue;
149	        }
150	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
151	            return Some(rest.to_string());
152	        }
153	    }
154	    None
155	}
