189	fn rbtdrk_git_add_and_commit_paths(
190	    root: &Path,
191	    files: &[&str],
192	    message: &str,
193	) -> Result<(), String> {
194	    let mut add_args: Vec<&str> = vec!["add"];
195	    add_args.extend_from_slice(files);
196	    let add = Command::new("git")
197	        .args(&add_args)
198	        .current_dir(root)
199	        .output()
200	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
201	    if !add.status.success() {
202	        return Err(format!(
203	            "rbtdrk: git add failed (exit {}): {}",
204	            add.status.code().unwrap_or(-1),
205	            String::from_utf8_lossy(&add.stderr).trim()
206	        ));
207	    }
208	    let commit = Command::new("git")
209	        .args(["commit", "-m", message])
210	        .current_dir(root)
211	        .output()
212	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
213	    if !commit.status.success() {
214	        return Err(format!(
215	            "rbtdrk: git commit failed (exit {}): {}",
216	            commit.status.code().unwrap_or(-1),
217	            String::from_utf8_lossy(&commit.stderr).trim()
218	        ));
219	    }
220	    Ok(())
221	}
