238	/// Idempotently install canc-/canr- prefixes. CLOUD_PREFIX lands in rbrd.env,
239	/// RUNTIME_PREFIX lands in rbrr.env. Returns Ok without committing when both
240	/// already match the canonical markers; otherwise rewrites both files and
241	/// commits in one go.
242	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
243	    let rbrr = root.join(RBTDRK_RBRR_FILE);
244	    let rbrd = root.join(RBTDRK_RBRD_FILE);
245	    let tincture = rbtdrk_burs_tincture()?;
246	    let cloud_target = rbtdrk_canonical_cloud_prefix(&tincture);
247	    let runtime_target = rbtdrk_canonical_runtime_prefix(&tincture);
248	
249	    let cloud = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
250	    let runtime =
251	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
252	    if cloud == cloud_target && runtime == runtime_target {
253	        return Ok(());
254	    }
255	
256	    if cloud != cloud_target {
257	        let content = std::fs::read_to_string(&rbrd)
258	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
259	        let new_content = rbtdrk_replace_env_fields(
260	            &content,
261	            &[(RBTDRK_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
262	        );
263	        std::fs::write(&rbrd, &new_content)
264	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
265	    }
266	
267	    if runtime != runtime_target {
268	        let content = std::fs::read_to_string(&rbrr)
269	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
270	        let new_content = rbtdrk_replace_env_fields(
271	            &content,
272	            &[(RBTDRK_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
273	        );
274	        std::fs::write(&rbrr, &new_content)
275	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
276	    }
277	
278	    let commit_msg = format!(
279	        "canonical-establish fixture: install canonical prefixes ({}/{})",
280	        cloud_target, runtime_target
281	    );
282	    rbtdrk_git_add_and_commit_paths(
283	        root,
284	        &[RBTDRK_RBRR_FILE, RBTDRK_RBRD_FILE],
285	        &commit_msg,
286	    )
287	}
