447	
448	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
449	/// fresh canest moniker, levies the depot, cross-checks project_id from
450	/// fact-file against the RBDC compose derivation.
451	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
452	    let probe = rbtdrb_Probe {
453	        name: "rbrr.env present",
454	        check: rbtdrk_probe_rbrr_present,
455	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
456	    };
457	    if let Err(v) = rbtdrb_assert(&probe) {
458	        return v;
459	    }
460	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
461	}
