2511	/// Parse a rekon stdout line for a given basename and return whether the
2512	/// EXISTS column reads "yes". Returns false if the basename row is absent.
2513	/// Rekon prints rows of `  <basename>  <yes|no>  <path-or-(absent)>`.
2514	pub(crate) fn rbtdrc_rekon_basename_yes(stdout: &str, basename: &str) -> bool {
2515	    for line in stdout.lines() {
2516	        let mut fields = line.split_whitespace();
2517	        if fields.next() == Some(basename) {
2518	            return fields.next() == Some("yes");
