2524	/// Docker wrapper: capture RootFS layer DiffIDs as a JSON array string.
2525	/// Layer DiffIDs are SHA256s of uncompressed layer file content — byte-preserved
2526	/// across registry round-trips even when manifest envelope normalizes (e.g.,
2527	/// multi-arch index → single-platform manifest). Robust round-trip fingerprint.
2528	pub(crate) fn rbtdrc_docker_layers_capture(image_ref: &str) -> Result<String, String> {
2529	    let output = Command::new("docker")
2530	        .args(["inspect", "--format={{json .RootFS.Layers}}", image_ref])
2531	        .output()
2532	        .map_err(|e| format!("docker inspect exec failed: {}", e))?;
2533	    if !output.status.success() {
2534	        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
2535	        return Err(format!(
2536	            "docker inspect {} exited {}: {}",
2537	            image_ref,
2538	            output.status.code().unwrap_or(-1),
2539	            stderr
2540	        ));
2541	    }
2542	    let layers = String::from_utf8_lossy(&output.stdout).trim().to_owned();
2543	    if layers.is_empty() || layers == "null" {
2544	        return Err(format!("docker inspect {} returned empty layers", image_ref));
2545	    }
2546	    Ok(layers)
