2582	fn rbtdrc_hallmark_lifecycle(dir: &Path) -> rbtdre_Verdict {
2583	    rbtdrc_with_ctx(|ctx| {
2584	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
2585	        if !ctx.project_root().join(vessel_dir).is_dir() {
2586	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2587	        }
2588	
2589	        // Step 1: baseline audit.
2590	        let _ = std::fs::write(dir.join("01-audit-baseline.txt"), "auditing baseline");
2591	        let baseline_audit = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_AUDIT_HALLMARKS, &[], &[]) {
2592	            Ok(r) if r.exit_code == 0 => r,
2593	            Ok(r) => return rbtdre_Verdict::Fail(format!("baseline audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2594	            Err(e) => return rbtdre_Verdict::Fail(format!("baseline audit invocation: {}", e)),
2595	        };
2596	        let _ = std::fs::write(dir.join("01-audit-baseline-stdout.txt"), &baseline_audit.stdout);
2597	        let baseline = match rbtdri_read_burv_facts_multi(&baseline_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2598	            Ok(v) => v,
2599	            Err(e) => return rbtdre_Verdict::Fail(format!("read baseline audit facts: {}", e)),
2600	        };
2601	        let _ = std::fs::write(dir.join("01-baseline-parsed.txt"), baseline.join("\n"));
2602	
2603	        // Step 2: ordain.
2604	        let _ = std::fs::write(dir.join("02-ordain.txt"), "ordaining busybox");
2605	        let ordain_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ORDAIN, &[vessel_dir], &[]) {
2606	            Ok(r) if r.exit_code == 0 => r,
2607	            Ok(r) => return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr)),
2608	            Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
2609	        };
2610	        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
2611	            Ok(v) => v,
2612	            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
2613	        };
2614	        let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
2615	
2616	        // Step 3: audit shows new hallmark added.
2617	        let _ = std::fs::write(dir.join("03-audit-after-ordain.txt"), "auditing after ordain");
2618	        let after_ordain_audit = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_AUDIT_HALLMARKS, &[], &[]) {
2619	            Ok(r) if r.exit_code == 0 => r,
2620	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2621	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain audit invocation: {}", e)),
2622	        };
2623	        let _ = std::fs::write(dir.join("03-audit-after-ordain-stdout.txt"), &after_ordain_audit.stdout);
2624	        let after_ordain = match rbtdri_read_burv_facts_multi(&after_ordain_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2625	            Ok(v) => v,
2626	            Err(e) => return rbtdre_Verdict::Fail(format!("read post-ordain audit facts: {}", e)),
2627	        };
2628	        let mut expected_after_ordain = baseline.clone();
2629	        expected_after_ordain.push(hallmark.clone());
2630	        expected_after_ordain.sort();
