316	
317	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
318	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
319	    let required = match rbtdrm_required_colophons(fixture) {
320	        Some(r) => r,
321	        None => {
322	            return Err(format!(
323	                "rbtd: unknown fixture '{}' — not registered in manifest",
324	                fixture
325	            ));
326	        }
327	    };
328	    for colophon in required {
329	        let found = manifest.split_whitespace().any(|token| token == *colophon);
330	        if !found {
331	            return Err(format!(
332	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
333	                colophon, fixture
334	            ));
335	        }
336	    }
337	    Ok(())
338	}
