            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
            RBTDRM_COLOPHON_SUMMON,
            RBTDRM_COLOPHON_PLUMB_FULL,
            RBTDRM_COLOPHON_PLUMB_COMPACT,
